<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    --bg: #14161a;
    --panel: #1e2128;
    --border: #2e3340;
    --text: #d7dae0;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: var(--bg);
    color: var(--text);
    font-family: "Segoe UI", system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 20px;
    font-weight: 600;
    letter-spacing: 1px;
    color: #aab2c0;
  }
  #toolbar {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 14px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: background .15s, border-color .15s, transform .05s;
  }
  button:hover { background: #262b35; }
  button:active { transform: scale(0.96); }
  button.selected {
    border-color: #6ea8ff;
    background: #223049;
    box-shadow: 0 0 0 1px #6ea8ff inset;
  }
  .swatch {
    width: 12px;
    height: 12px;
    border-radius: 3px;
    display: inline-block;
  }
  #clear {
    border-color: #5a3540;
  }
  #clear:hover { background: #3a232b; }
  #sand {
    width: 480px;
    height: 480px;
    max-width: 95vw;
    max-height: 95vw;
    image-rendering: pixelated;
    border: 1px solid var(--border);
    border-radius: 6px;
    background: #0b0d10;
    cursor: crosshair;
    touch-action: none;
  }
  #hint { font-size: 12px; color: #6b7280; margin: 0; }
</style>
</head>
<body>
  <h1>FALLING SAND</h1>
  <div id="toolbar">
    <button id="mat-sand"><span class="swatch" style="background:#e0c068"></span>Sand</button>
    <button id="mat-water"><span class="swatch" style="background:#3f8fe8"></span>Water</button>
    <button id="mat-wall"><span class="swatch" style="background:#8a8f9a"></span>Wall</button>
    <button id="mat-acid"><span class="swatch" style="background:#7ef542"></span>Acid</button>
    <button id="mat-empty"><span class="swatch" style="background:#0b0d10;border:1px solid #444"></span>Erase</button>
    <button id="clear">Clear</button>
  </div>
  <canvas id="sand" width="120" height="120"></canvas>
  <p id="hint">Click &amp; drag to paint the selected material.</p>

<script>
(function () {
  "use strict";

  // ---- Grid setup -------------------------------------------------------
  var W = 120, H = 120;
  var EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  var NAMES = ["empty", "sand", "water", "wall", "acid"];
  var IDS = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };

  var grid = new Uint8Array(W * H);
  var moved = new Uint8Array(W * H);

  function inb(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }
  function at(x, y) { return grid[y * W + x]; }
  function put(x, y, m) { grid[y * W + x] = m; }

  // ---- Simulation -------------------------------------------------------
  function trySandFall(x, y) {
    var i = y * W + x;
    if (y + 1 >= H) return false; // bottom boundary is solid
    var b = at(x, y + 1);
    if (b === EMPTY) {
      put(x, y + 1, SAND); grid[i] = EMPTY;
      moved[(y + 1) * W + x] = 1;
      return true;
    }
    if (b === WATER || b === ACID) { // sand sinks: swap
      put(x, y + 1, SAND); grid[i] = b;
      moved[(y + 1) * W + x] = 1; moved[i] = 1;
      return true;
    }
    // slide diagonally, random side first
    var first = Math.random() < 0.5 ? -1 : 1;
    var dirs = [first, -first];
    for (var k = 0; k < 2; k++) {
      var nx = x + dirs[k];
      if (nx >= 0 && nx < W && at(nx, y + 1) === EMPTY && at(nx, y) === EMPTY) {
        put(nx, y + 1, SAND); grid[i] = EMPTY;
        moved[(y + 1) * W + nx] = 1;
        return true;
      }
    }
    return false;
  }

  function tryLiquidMove(x, y, self) {
    var i = y * W + x;
    if (y + 1 < H && at(x, y + 1) === EMPTY) {
      put(x, y + 1, self); grid[i] = EMPTY;
      moved[(y + 1) * W + x] = 1;
      return true;
    }
    var first = Math.random() < 0.5 ? -1 : 1;
    var dirs = [first, -first], k, nx;
    // diagonal flow
    for (k = 0; k < 2; k++) {
      nx = x + dirs[k];
      if (nx >= 0 && nx < W && y + 1 < H &&
          at(nx, y + 1) === EMPTY && at(nx, y) === EMPTY) {
        put(nx, y + 1, self); grid[i] = EMPTY;
        moved[(y + 1) * W + nx] = 1;
        return true;
      }
    }
    // horizontal spread
    for (k = 0; k < 2; k++) {
      nx = x + dirs[k];
      if (nx >= 0 && nx < W && at(nx, y) === EMPTY) {
        put(nx, y, self); grid[i] = EMPTY;
        moved[y * W + nx] = 1;
        return true;
      }
    }
    return false;
  }

  function updateAcid(x, y) {
    // dissolve a sand/wall neighbour below or beside
    var i = y * W + x;
    var targets = [[x, y + 1], [x - 1, y], [x + 1, y]];
    for (var k = 0; k < 3; k++) {
      var tx = targets[k][0], ty = targets[k][1];
      if (!inb(tx, ty)) continue;
      var t = at(tx, ty);
      if (t === SAND || t === WALL) {
        put(tx, ty, EMPTY);
        if (Math.random() < 0.3) grid[i] = EMPTY; // acid sometimes consumed
        moved[i] = 1;
        return;
      }
    }
    tryLiquidMove(x, y, ACID);
  }

  function step() {
    moved.fill(0);
    // bottom-row-up: a particle moves at most one cell per step
    for (var y = H - 1; y >= 0; y--) {
      var ltr = Math.random() < 0.5;
      for (var s = 0; s < W; s++) {
        var x = ltr ? s : W - 1 - s;
        var i = y * W + x;
        if (moved[i]) continue;
        var m = grid[i];
        if (m === SAND) trySandFall(x, y);
        else if (m === WATER) tryLiquidMove(x, y, WATER);
        else if (m === ACID) updateAcid(x, y);
        // WALL and EMPTY never move
      }
    }
  }

  // ---- Rendering --------------------------------------------------------
  var canvas = document.getElementById("sand");
  var ctx = canvas.getContext("2d");
  var img = ctx.createImageData(W, H);
  var px = img.data;

  // static per-cell brightness noise for texture
  var noise = new Float32Array(W * H);
  for (var n = 0; n < noise.length; n++) noise[n] = 0.88 + Math.random() * 0.24;

  var COLORS = [
    [11, 13, 16],    // empty
    [224, 192, 104], // sand
    [63, 143, 232],  // water
    [138, 143, 154], // wall
    [126, 245, 66]   // acid
  ];

  function render() {
    for (var i = 0; i < W * H; i++) {
      var c = COLORS[grid[i]];
      var f = grid[i] === EMPTY ? 1 : noise[i];
      var o = i * 4;
      px[o] = c[0] * f;
      px[o + 1] = c[1] * f;
      px[o + 2] = c[2] * f;
      px[o + 3] = 255;
    }
    ctx.putImageData(img, 0, 0);
  }

  function loop() {
    step();
    render();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);

  // ---- Painting ---------------------------------------------------------
  var current = SAND;
  var painting = false;
  var BRUSH = 2;

  function paintAt(clientX, clientY) {
    var r = canvas.getBoundingClientRect();
    var gx = Math.floor((clientX - r.left) / r.width * W);
    var gy = Math.floor((clientY - r.top) / r.height * H);
    for (var dy = -BRUSH; dy <= BRUSH; dy++) {
      for (var dx = -BRUSH; dx <= BRUSH; dx++) {
        if (dx * dx + dy * dy > BRUSH * BRUSH) continue;
        var x = gx + dx, y = gy + dy;
        if (inb(x, y)) put(x, y, current);
      }
    }
    render();
  }

  canvas.addEventListener("pointerdown", function (e) {
    painting = true;
    canvas.setPointerCapture(e.pointerId);
    paintAt(e.clientX, e.clientY);
    e.preventDefault();
  });
  canvas.addEventListener("pointermove", function (e) {
    if (painting) paintAt(e.clientX, e.clientY);
  });
  canvas.addEventListener("pointerup", function () { painting = false; });
  canvas.addEventListener("pointercancel", function () { painting = false; });

  // ---- Buttons ----------------------------------------------------------
  var matButtons = {
    "mat-sand": SAND,
    "mat-water": WATER,
    "mat-wall": WALL,
    "mat-acid": ACID,
    "mat-empty": EMPTY
  };
  Object.keys(matButtons).forEach(function (id) {
    var btn = document.getElementById(id);
    btn.addEventListener("click", function () {
      current = matButtons[id];
      Object.keys(matButtons).forEach(function (other) {
        document.getElementById(other).classList.toggle("selected", other === id);
      });
    });
  });
  document.getElementById("mat-sand").classList.add("selected");

  function clearGrid() {
    grid.fill(EMPTY);
    render();
  }
  document.getElementById("clear").addEventListener("click", clearGrid);

  // ---- Programmatic API -------------------------------------------------
  window.sim = {
    w: W,
    h: H,
    tick: function (n) {
      var count = Math.max(0, Math.floor(n || 1));
      for (var k = 0; k < count; k++) step();
      render();
    },
    get: function (x, y) {
      if (!inb(x, y)) return "wall"; // out of bounds acts solid
      return NAMES[at(x, y)];
    },
    set: function (x, y, material) {
      if (!inb(x, y)) return;
      var m = IDS[material];
      if (m === undefined) throw new Error("unknown material: " + material);
      put(x, y, m);
      render();
    },
    clear: clearGrid
  };

  render();
})();
</script>
</body>
</html>
